mapper.select:
select record_id, username, course_name, progress_percent, last_study_time, status from study_records
and deleted = false
and (username like concat('%', #{keyword}, '%') or course_name like concat('%', #{keyword}, '%'))
and status = #{status}
order by record_id desc limit #{pageSize} offset #{offset}

mapper.update:
update study_records
set deleted = true,
    updated_at = #{updatedAt},
    updated_by = #{updatedBy}
where record_id = #{recordId}
  and deleted = false
